import { useMemo } from 'react';
import {
  Shield, KeyRound, CheckCircle2, Lock,
  Eye, Plus, Pencil, Trash2, Settings2, HelpCircle, Eraser, Unlink,
  Link, RotateCcw, Power, PowerOff, BadgeCheck, Flag, Ban, CircleMinus,
  type LucideIcon,
} from 'lucide-react';
import { useAuth } from '@/shared/AuthContext';
import { useQuery } from '@tanstack/react-query';
import { queryKeys } from '@/lib/queryKeys';
import { permissionService as accountService } from '@/api/auth/permissionService';
import { Card, CardContent } from '@/shadcn/components/ui/card';
import { Badge } from '@/shadcn/components/ui/badge';
import { Alert, AlertTitle, AlertDescription } from '@/shadcn/components/ui/alert';
import { Skeleton } from '@/shadcn/components/ui/skeleton';
import { Separator } from '@/shadcn/components/ui/separator';

// ── Action → icon mapping — change here to update the whole page ──────────────
const ACTION_ICONS: Record<string, LucideIcon> = {
  Read:       Eye,
  Create:     Plus,
  Update:     Pencil,
  Delete:     Trash2,
  HardDelete: Eraser,
  Allocate:   Link,
  Deallocate: Unlink,
  Restore:    RotateCcw,
  Activate:   Power,
  Deactivate: PowerOff,
  Approve:    BadgeCheck,
  Finalize:   Flag,
  Reject:     Ban,
  Consume:    CircleMinus,
  Manage:     Settings2,
};
const DEFAULT_ACTION_ICON: LucideIcon = HelpCircle;
// ─────────────────────────────────────────────────────────────────────────────

interface Permission {
  id: string;
  name: string;
  displayName: string;
  description?: string;
  resource: string;
  action: string;
}

interface PermissionGroup {
  resource: string;
  permissions: Permission[];
}

const splitPascalCase = (str: string) => str.replace(/([A-Z])/g, ' $1').trim();

const MyPermissions = () => {
  const { permissions: userPerms, isLoading: authLoading } = useAuth();

  const { data: allGroups = [], isLoading: permsLoading } = useQuery<PermissionGroup[]>({
    queryKey: queryKeys.permissionsCatalog(),
    queryFn: () => accountService.getAllPermissionsGrouped(),
    staleTime: Infinity,
  });

  const loading = authLoading || permsLoading;

  const processedGroups = useMemo(() =>
    allGroups.map(group => ({
      ...group,
      grantedCount: group.permissions.filter(p => userPerms.includes(p.name)).length,
      totalCount: group.permissions.length
    })).filter(group => group.totalCount > 0),
    [allGroups, userPerms]
  );

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'calc(var(--section-padding) * 1.75)' }}>
      <div className="flex items-center gap-3">
        <div className="size-12 flex items-center justify-center rounded-lg bg-primary/10 shrink-0">
          <KeyRound className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight text-foreground">My Permissions</h1>
          <p className="text-sm text-muted-foreground mt-0.5">A summary of your current system privileges and restrictions.</p>
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col gap-[calc(var(--section-padding)*0.7)]">
          {[1, 2, 3].map(i => (
            <div key={i} className="space-y-3">
              <div className="flex items-center gap-3">
                <Skeleton className="h-3 w-24" />
                <Skeleton className="h-px flex-1" />
                <Skeleton className="h-3 w-20" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-[calc(var(--section-padding)*0.7)]">
                {[1, 2, 3, 4].map(j => (
                  <Skeleton key={j} className="h-20 rounded-xl" />
                ))}
              </div>
            </div>
          ))}
        </div>
      ) : processedGroups.length > 0 ? (
        <div className="flex flex-col" style={{ gap: 'calc(var(--section-padding) * 1.75)' }}>
          {processedGroups.map((group) => (
            <div key={group.resource} className="flex flex-col gap-[calc(var(--section-padding)*0.7)]">
              <div className="flex items-center gap-3">
                <span className="text-xs font-semibold text-foreground uppercase tracking-widest whitespace-nowrap">
                  {splitPascalCase(group.resource)}
                </span>
                <Separator className="flex-1" />
                <span className="text-xs text-muted-foreground whitespace-nowrap">
                  {group.grantedCount} / {group.totalCount} granted
                </span>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-[calc(var(--section-padding)*0.7)]">
                {group.permissions.map((perm) => {
                  const isGranted = userPerms.includes(perm.name);
                  const ActionIcon = ACTION_ICONS[perm.action] ?? DEFAULT_ACTION_ICON;
                  return (
                    <Card key={perm.id} size="sm" className={!isGranted ? 'opacity-50' : undefined}>
                      <CardContent className="flex items-start gap-3">
                        <div className={`shrink-0 size-8 rounded-lg flex items-center justify-center ${
                          isGranted ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'
                        }`}>
                          {isGranted ? <CheckCircle2 size={16} /> : <Lock size={15} />}
                        </div>
                        <div className="flex flex-col min-w-0 flex-1 gap-2">
                          <div className="flex items-center gap-2 min-w-0">
                            <span className="text-sm font-medium leading-tight line-clamp-2 flex-1">
                              {perm.displayName || perm.name}
                            </span>
                            <Badge variant={isGranted ? 'secondary' : 'outline'} className="shrink-0">
                              {isGranted ? <ActionIcon /> : <Lock />}
                              {isGranted ? splitPascalCase(perm.action) : 'Restricted'}
                            </Badge>
                          </div>
                          {perm.description && (
                            <p className="text-xs text-muted-foreground leading-snug line-clamp-3">
                              {perm.description}
                            </p>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            </div>
          ))}

          <Alert>
            <Lock />
            <AlertTitle>Security Note</AlertTitle>
            <AlertDescription>
              These permissions are assigned based on your active roles. If you require additional access, please contact your system administrator.
            </AlertDescription>
          </Alert>
        </div>
      ) : (
        <div className="py-20 bg-card rounded-xl border border-dashed text-center">
          <Shield size={40} className="mx-auto text-muted-foreground/30 mb-4" />
          <h3 className="text-base font-semibold text-foreground mb-1">No Permissions Assigned</h3>
          <p className="text-sm text-muted-foreground max-w-xs mx-auto">
            You currently have no active permissions. Please contact your administrator for account provisioning.
          </p>
        </div>
      )}
    </div>
  );
};

export default MyPermissions;
